-- CA Revised Uniform LLC Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_008', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 17701.01-17713.13 (California Revised Uniform Limited Liability Company Act)', 'Corp Code § 17701+', 'California Revised Uniform LLC Act', 'Comprehensive statute governing the formation, operation, management, and dissolution of limited liability companies in California. Replaced the Beverly-Killea LLC Act effective January 1, 2014. Provides default rules that may be modified by operating agreement except for non-waivable provisions.', '["Articles of Organization filed with Secretary of State (§ 17702.01)","Operating agreement governs relations among members and managers (§ 17701.10)","Member-managed unless operating agreement provides for manager-managed (§ 17704.07)","Duty of loyalty and duty of care owed by members/managers (§ 17704.09)","Annual Statement of Information required (§ 17702.09)","Registered agent for service of process required (§ 17701.13)","Transferability of membership interests restricted by default (§ 17704.02)","Dissolution triggered by events in § 17707.01"]', '[{"section":"17701.04","description":"Formation — Articles of Organization filing requirements"},{"section":"17701.10","description":"Operating agreement — scope, enforceability, non-waivable provisions"},{"section":"17702.09","description":"Statement of Information — biennial filing requirement"},{"section":"17704.07","description":"Management — member-managed vs. manager-managed structures"},{"section":"17704.09","description":"Standards of conduct — duty of loyalty, duty of care, obligation of good faith and fair dealing"},{"section":"17706.02","description":"Member dissociation — wrongful vs. rightful"},{"section":"17707.01","description":"Dissolution events and procedures"},{"section":"17713.04","description":"Merger and conversion procedures"}]', '["articles_of_organization","operating_agreement","statement_of_information","certificate_of_dissolution","membership_interest_assignment","manager_resolution"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State', 1, 1, datetime('now'), datetime('now'));

-- CA General Corporation Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_009', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 100-2319 (California General Corporation Law)', 'Corp Code § 100+', 'California General Corporation Law', 'Primary statutory framework governing the formation, governance, and dissolution of general stock corporations in California. Establishes board fiduciary duties, shareholder rights, merger procedures, and corporate formalities. California imposes stricter fiduciary standards than Delaware, including cumulative voting rights by default and broader shareholder inspection rights.', '["Articles of Incorporation filed with Secretary of State (§ 200)","Bylaws adopted by incorporator or board (§ 212)","Annual meeting of shareholders required (§ 600)","Board of directors minimum duties of care and loyalty (§§ 309-310)","Annual Statement of Information within 90 days of fiscal year end (§ 1502)","Cumulative voting in director elections by default (§ 708.1)","Shareholder inspection rights for books and records (§ 1601)","Dissolution requires board resolution and shareholder approval (§ 1900)"]', '[{"section":"200","description":"Articles of Incorporation — required and optional provisions"},{"section":"212","description":"Bylaws — adoption, amendment, and required content"},{"section":"309","description":"Duty of care — informed business judgment standard"},{"section":"310","description":"Interested director transactions — approval requirements"},{"section":"600","description":"Annual meeting of shareholders — notice and quorum"},{"section":"708.1","description":"Cumulative voting rights in director elections"},{"section":"1501","description":"Annual report to shareholders"},{"section":"1502","description":"Statement of Information — annual filing with Secretary of State"},{"section":"1601","description":"Shareholder inspection of books and records"},{"section":"1900-1905","description":"Dissolution procedures — voluntary and involuntary"}]', '["articles_of_incorporation","bylaws","board_resolution","shareholder_agreement","annual_report","statement_of_information","stock_certificate","proxy_statement"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State / California Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Revised Uniform Partnership Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_010', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 16100-16962 (California Revised Uniform Partnership Act)', 'Corp Code § 16100+', 'California Revised Uniform Partnership Act', 'Governs general partnerships including formation by association, partner fiduciary duties, joint and several liability for partnership obligations, dissociation, and dissolution. A partnership is an entity distinct from its partners under RUPA. Partners are default agents of the partnership for carrying on business in the ordinary course.', '["Partnership formed by association of two or more persons carrying on business for profit (§ 16202)","Each partner is agent of the partnership (§ 16301)","Partners jointly and severally liable for partnership obligations (§ 16306)","Duty of loyalty — account for profits, refrain from self-dealing, refrain from competing (§ 16404(b))","Duty of care — refrain from grossly negligent or reckless conduct (§ 16404(c))","Partnership agreement may not eliminate duty of loyalty or unreasonably reduce duty of care (§ 16103)","Partner dissociation — rightful or wrongful (§§ 16601-16603)","Dissolution and winding up (§§ 16801-16807)"]', '[{"section":"16202","description":"Formation — carrying on business for profit creates partnership"},{"section":"16301","description":"Each partner is agent of the partnership"},{"section":"16306","description":"Joint and several liability of partners for all partnership obligations"},{"section":"16401","description":"Partner rights to distributions and access to books/records"},{"section":"16404","description":"General standards of partner conduct — loyalty, care, good faith"},{"section":"16502","description":"Partner right to an accounting"},{"section":"16601","description":"Dissociation events"},{"section":"16801","description":"Events causing dissolution and winding up"}]', '["partnership_agreement","statement_of_partnership","partner_accounting","dissolution_notice","buyout_agreement","statement_of_dissociation"]', '["corporate-legal-architecture-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Revised Uniform LP Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_011', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 15900-15912.07 (California Revised Uniform Limited Partnership Act)', 'Corp Code § 15900+', 'California Revised Uniform Limited Partnership Act', 'Governs formation and operation of limited partnerships in California. Requires at least one general partner with unlimited liability and one limited partner whose liability is limited to their contribution. Certificate of Limited Partnership must be filed with the Secretary of State. Eliminates the control rule — limited partners may participate in management without losing liability protection.', '["Certificate of Limited Partnership filed with Secretary of State (§ 15902.01)","At least one general partner and one limited partner required (§ 15901.02)","General partner has unlimited personal liability (§ 15904.04)","Limited partner liability limited to contribution absent guarantees (§ 15903.03)","Limited partners may participate in management without losing liability shield (§ 15903.03)","Partnership agreement governs relations among partners (§ 15901.10)","Annual Statement of Information required","General partner owes fiduciary duties; limited partner does not by default (§ 15905.08)"]', '[{"section":"15901.02","description":"Definitions — general partner, limited partner"},{"section":"15902.01","description":"Certificate of Limited Partnership — formation and filing"},{"section":"15903.03","description":"Limited partner liability — no control rule"},{"section":"15904.04","description":"General partner — agency authority and personal liability"},{"section":"15905.08","description":"General partner fiduciary duties of loyalty and care"},{"section":"15906.01","description":"Dissociation of limited partner"},{"section":"15908.01","description":"Dissolution events and winding up"},{"section":"15911.01","description":"Merger and conversion"}]', '["certificate_of_limited_partnership","partnership_agreement","statement_of_information","capital_contribution_agreement","dissolution_notice","certificate_of_cancellation"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State', 1, 1, datetime('now'), datetime('now'));

-- CA Nonprofit Corporation Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_012', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 5000-10841 (California Nonprofit Corporation Law)', 'Corp Code § 5000+', 'California Nonprofit Corporation Law', 'Governs three types of nonprofit corporations: public benefit (§§ 5110-6910), mutual benefit (§§ 7110-8910), and religious (§§ 9110-9690). Public benefit corporations operate for public or charitable purposes and are subject to Attorney General oversight. Board members owe fiduciary duties and must avoid self-dealing transactions. Assets of a dissolved public benefit corporation must be distributed to another public benefit organization.', '["Articles of Incorporation stating nonprofit purpose (§ 5130/7130/9130)","Board of directors required — no fewer than one for mutual benefit, three for public benefit (§ 5151/7151)","No distribution of profits to members or directors (§ 5410)","Attorney General oversight of public benefit corporations (§ 5250)","Annual Statement of Information required","Self-dealing transaction approval under § 5233","IRS Form 1023/1024 for federal tax exemption","FTB Form 3500 for California tax exemption","Dissolution — assets distributed to qualifying charitable organization (§ 6716)"]', '[{"section":"5110-5510","description":"Public benefit corporation — formation and governance"},{"section":"5150","description":"Articles of Incorporation — required provisions"},{"section":"5233","description":"Self-dealing transactions — board approval requirements"},{"section":"5250","description":"Attorney General supervisory powers over public benefit corps"},{"section":"6716","description":"Dissolution — distribution of assets to charitable purpose"},{"section":"7110-7151","description":"Mutual benefit corporation provisions"},{"section":"9110-9690","description":"Religious corporation provisions"},{"section":"5520-5617","description":"Mergers of nonprofit corporations"}]', '["articles_of_incorporation","bylaws","conflict_of_interest_policy","Form_1023","FTB_3500","board_resolution","annual_report","dissolution_plan"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State / Attorney General', 0, 1, datetime('now'), datetime('now'));

-- CA Secretary of State Filing Requirements
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_013', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code § 12190 et seq.; Cal. Corp. Code §§ 1502, 17702.09', 'Gov Code § 12190+', 'California Secretary of State — Business Entity Filing Requirements', 'Secretary of State is the filing office for all California business entities. Formation documents, Statements of Information, amendments, mergers, conversions, and dissolutions must be filed with the SOS. Failure to file the required Statement of Information results in suspension or forfeiture. The SOS maintains the public business entity database and issues Certificates of Good Standing.', '["Articles/Certificate filed to create entity (Corp Code §§ 200, 17702.01, 15902.01)","Statement of Information filed biennially for LLCs, annually for corporations (Corp Code §§ 1502, 17702.09)","Registered agent for service of process required","Amendments to formation documents must be filed","Certificate of Good Standing available upon request","Failure to file SOI leads to suspension by FTB","Foreign entity registration required before transacting business (Corp Code § 2105)","Name reservation available for 60 days (Corp Code § 201.5)"]', '[{"section":"Gov Code 12190","description":"Secretary of State — powers and duties regarding business filings"},{"section":"Corp Code 1502","description":"Corporation — annual Statement of Information"},{"section":"Corp Code 17702.09","description":"LLC — biennial Statement of Information"},{"section":"Corp Code 2105","description":"Foreign corporation qualification to transact business"},{"section":"Corp Code 2117","description":"Penalties for transacting business without qualification"}]', '["articles_of_organization","articles_of_incorporation","statement_of_information","certificate_of_good_standing","name_reservation","foreign_qualification","amendment_filing"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State', 0, 1, datetime('now'), datetime('now'));

-- CA Franchise Tax Board — Annual Minimum Franchise Tax
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_014', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Rev. & Tax. Code §§ 17941, 23151, 23153 (California Franchise Tax)', 'RTC §§ 17941/23153', 'California Franchise Tax Board — Annual Minimum Franchise Tax', 'Every LLC, corporation, and limited partnership doing business in California or organized under California law must pay an annual minimum franchise tax of $800 to the Franchise Tax Board. First-year exemption applies to LLCs but not corporations. LLCs with gross receipts exceeding $250,000 pay an additional annual fee ranging from $900 to $11,790 under RTC § 17942. Failure to pay results in entity suspension and loss of right to transact business.', '["$800 annual minimum franchise tax for LLCs (§ 17941)","$800 annual minimum franchise tax for corporations (§ 23153)","LLC fee based on gross receipts: $900 ($250K-$500K), $2,500 ($500K-$1M), $6,000 ($1M-$5M), $11,790 ($5M+) (§ 17942)","First-year LLC exemption from $800 minimum (§ 17941(d))","Tax due on 15th day of 4th month of taxable year","Entity suspended for nonpayment — cannot transact business, file suit, or defend actions","Revivor requires payment of all back taxes, penalties, and interest","SOS suspends entity upon FTB certificate of noncompliance"]', '[{"section":"17941","description":"Annual tax on LLCs — $800 minimum"},{"section":"17942","description":"LLC annual fee based on gross California receipts"},{"section":"23151","description":"Corporate franchise tax rate — 8.84% of net income"},{"section":"23153","description":"Minimum franchise tax — $800 for corporations"},{"section":"23301","description":"Suspension powers of FTB for nonpayment"},{"section":"23305","description":"Revivor procedures to restore suspended entity"}]', '["FTB_return","franchise_tax_payment","LLC_fee_calculation","suspension_notice","revivor_application","certificate_of_revivor"]', '["corporate-legal-architecture-audit"]', 'California Franchise Tax Board', 0, 1, datetime('now'), datetime('now'));


