-- UCC Article 2 — Sale of Goods
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_015', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Com. Code §§ 2101-2725 (UCC Article 2 — Sales)', 'Com Code § 2101+', 'UCC Article 2 — Sale of Goods', 'Governs transactions in goods (movable property). Establishes rules for contract formation, warranties, performance, breach, and remedies in commercial sales. The statute of frauds requires a writing for sales of goods priced at $500 or more. Applies only to goods, not services or real property. Merchant rules impose heightened obligations on parties who regularly deal in goods of the kind.', '["Contract formation — offer, acceptance, and consideration (§ 2204)","Statute of Frauds — writing required for goods $500+ (§ 2201)","Express warranties by affirmation, description, or sample (§ 2313)","Implied warranty of merchantability (§ 2314)","Implied warranty of fitness for particular purpose (§ 2315)","Perfect tender rule — buyer may reject if goods fail to conform (§ 2601)","Cover — buyer may purchase substitute goods and recover difference (§ 2712)","4-year statute of limitations from tender of delivery (§ 2725)"]', '[{"section":"2201","description":"Statute of Frauds — contracts for sale of goods $500 or more"},{"section":"2204","description":"Formation — contract may be made in any manner sufficient to show agreement"},{"section":"2302","description":"Unconscionable contracts or clauses"},{"section":"2313","description":"Express warranties — affirmation of fact or promise"},{"section":"2314","description":"Implied warranty of merchantability"},{"section":"2315","description":"Implied warranty of fitness for particular purpose"},{"section":"2601","description":"Buyer right to reject — perfect tender rule"},{"section":"2712","description":"Cover — buyer remedy to purchase substitute goods"},{"section":"2725","description":"Statute of limitations — 4 years from tender of delivery"}]', '["purchase_order","sales_contract","invoice","warranty_disclaimer","UCC_complaint","demand_letter"]', '["corporate-legal-architecture-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- UCC Article 3 — Negotiable Instruments
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_016', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Com. Code §§ 3101-3605 (UCC Article 3 — Negotiable Instruments)', 'Com Code § 3101+', 'UCC Article 3 — Negotiable Instruments', 'Governs promissory notes and drafts (including checks). Establishes requirements for negotiability, holder in due course status, liability of parties, and discharge. A holder in due course takes the instrument free of most defenses except real defenses such as fraud in the factum, duress, and incapacity. Revised Article 3 adopted in California effective 1993.', '["Negotiability requirements — unconditional promise/order, fixed amount of money, payable on demand or at definite time, payable to order or bearer (§ 3104)","Holder in due course — takes for value, in good faith, without notice of defenses (§ 3302)","Real defenses survive HDC status — infancy, duress, incapacity, illegality, fraud in factum (§ 3305(a))","Presentment, dishonor, and notice requirements (§§ 3501-3505)","Drawer liability on dishonored draft (§ 3414)","Indorser liability on dishonored instrument (§ 3415)","Discharge by payment or cancellation (§§ 3601-3604)"]', '[{"section":"3104","description":"Negotiable instrument — definition and formal requirements"},{"section":"3201","description":"Negotiation — transfer of possession plus indorsement"},{"section":"3302","description":"Holder in due course — requirements and protections"},{"section":"3305","description":"Defenses and claims in recoupment — real vs. personal defenses"},{"section":"3401","description":"Signature — liability only attaches to those who sign"},{"section":"3414","description":"Obligation of drawer on dishonored draft"},{"section":"3415","description":"Obligation of indorser on dishonored instrument"},{"section":"3601","description":"Discharge and payment"}]', '["promissory_note","check","draft","indorsement","dishonor_notice","demand_for_payment"]', '["corporate-legal-architecture-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- UCC Article 9 — Secured Transactions
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_017', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Com. Code §§ 9101-9809 (UCC Article 9 — Secured Transactions)', 'Com Code § 9101+', 'UCC Article 9 — Secured Transactions', 'Governs security interests in personal property and fixtures. Establishes rules for attachment, perfection, priority, and enforcement of security interests. Perfection by filing a UCC-1 financing statement with the Secretary of State creates constructive notice. First-to-file-or-perfect rule determines priority among competing security interests. Comprehensive default and enforcement provisions in Part 6.', '["Security agreement must authenticate, describe collateral, and debtor must have rights in collateral (§ 9203)","Attachment requires value given, debtor rights in collateral, and authenticated security agreement (§ 9203)","Perfection by filing UCC-1 financing statement with Secretary of State (§ 9310)","Purchase money security interest (PMSI) superpriority (§ 9324)","First-to-file-or-perfect priority rule (§ 9322)","Financing statement effective for 5 years; continuation statement required (§§ 9515, 9516)","Default — secured party may repossess without breach of peace (§ 9609)","Commercially reasonable disposition of collateral after default (§ 9610)"]', '[{"section":"9203","description":"Attachment — security interest enforceable against debtor"},{"section":"9310","description":"Perfection — when filing required"},{"section":"9312","description":"Perfection by control or possession for specific collateral types"},{"section":"9322","description":"Priority among conflicting security interests — first to file or perfect"},{"section":"9324","description":"Purchase money security interest — superpriority rules"},{"section":"9501","description":"Filing office — Secretary of State for most collateral types"},{"section":"9515","description":"Duration of financing statement — 5 years"},{"section":"9609","description":"Secured party right to take possession after default"},{"section":"9610","description":"Disposition of collateral after default — commercially reasonable standard"}]', '["security_agreement","UCC_1_financing_statement","UCC_3_amendment","UCC_11_search","subordination_agreement","default_notice","disposition_notice"]', '["corporate-legal-architecture-audit"]', 'California Secretary of State / California Courts', 1, 1, datetime('now'), datetime('now'));


