-- Lanham Act — Trademark Registration
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_018', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC §§ 1051-1072 (Lanham Act — Registration)', 'Lanham Act §§ 1-22', 'Lanham Act — Trademark Registration', 'Federal trademark registration system administered by the USPTO. Registration on the Principal Register provides nationwide constructive notice, prima facie evidence of validity, and the ability to become incontestable after five years of continuous use. Applicants must demonstrate use in commerce or bona fide intent to use. The Trademark Trial and Appeal Board adjudicates opposition and cancellation proceedings.', '["Application on basis of use in commerce (§ 1051(a)) or intent to use (§ 1051(b))","Mark must be distinctive — inherently distinctive or acquired distinctiveness (§ 1052)","Bars to registration — deceptive, scandalous, primarily merely descriptive, primarily geographically descriptive, or likely to cause confusion (§ 1052)","Publication for opposition — 30-day period (§ 1063)","Statement of use required for ITU applications before registration issues (§ 1051(d))","Registration on Principal Register — constructive notice nationwide (§ 1072)","Incontestability after 5 years continuous use and § 15 affidavit (§ 1065)","Renewal every 10 years with § 8 declaration of continued use (§ 1058)"]', '[{"section":"1051(a)","description":"Application based on use in commerce"},{"section":"1051(b)","description":"Application based on bona fide intent to use"},{"section":"1052","description":"Bars to registration — grounds for refusal"},{"section":"1057","description":"Registration — constructive notice and prima facie evidence"},{"section":"1058","description":"Duration and renewal — § 8 affidavit of continued use"},{"section":"1063","description":"Opposition proceedings before TTAB"},{"section":"1064","description":"Cancellation proceedings"},{"section":"1065","description":"Incontestability — § 15 affidavit after 5 years continuous use"},{"section":"1072","description":"Constructive notice of registration"}]', '["trademark_application","specimen_of_use","office_action_response","statement_of_use","section_8_declaration","section_15_declaration","TTAB_opposition","registration_certificate"]', '["corporate-legal-architecture-audit"]', 'USPTO / TTAB', 1, 1, datetime('now'), datetime('now'));

-- Lanham Act — Trademark Infringement
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_019', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC § 1114 (Lanham Act § 32 — Trademark Infringement)', 'Lanham Act § 32', 'Lanham Act — Trademark Infringement', 'Creates a federal cause of action for infringement of registered trademarks. Any person who uses in commerce a reproduction, counterfeit, copy, or colorable imitation of a registered mark in connection with the sale or distribution of goods or services, where such use is likely to cause confusion, is liable for infringement. Remedies include injunctive relief, damages, profits, and in exceptional cases, attorneys fees.', '["Plaintiff must own a valid registered trademark","Defendant used mark in commerce without authorization","Use in connection with sale, offering for sale, distribution, or advertising of goods/services","Likelihood of confusion — multifactor test (Sleekcraft factors in 9th Circuit)","Willful infringement may result in treble damages (§ 1117(b))","Counterfeit marks — mandatory treble damages or statutory damages up to $2M per mark (§ 1117(c))","Innocent infringer defense limits remedy to injunction (§ 1114(2))"]', '[{"section":"1114(1)(a)","description":"Infringement of registered mark — use likely to cause confusion"},{"section":"1114(1)(b)","description":"Infringement by reproduction or counterfeit of registered mark"},{"section":"1114(2)","description":"Innocent infringer defense — printer/publisher limitation"},{"section":"1116","description":"Injunctive relief — TRO, preliminary and permanent injunction"},{"section":"1117(a)","description":"Recovery of profits, damages, and costs"},{"section":"1117(b)","description":"Treble damages for willful use of counterfeit mark"},{"section":"1117(c)","description":"Statutory damages for use of counterfeit mark — up to $2M per mark"}]', '["cease_and_desist_letter","trademark_infringement_complaint","likelihood_of_confusion_analysis","preliminary_injunction_motion","damages_calculation"]', '["corporate-legal-architecture-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Lanham Act — False Designation of Origin
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_020', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC § 1125(a) (Lanham Act § 43(a) — False Designation of Origin)', 'Lanham Act § 43(a)', 'Lanham Act — False Designation of Origin and Unfair Competition', 'Federal unfair competition statute providing a cause of action for false designation of origin and false advertising without requiring federal registration. Protects unregistered trademarks, trade dress, and prohibits false or misleading descriptions of fact in commercial advertising. Two prongs: (1) false association/endorsement and (2) false advertising. This is the primary federal vehicle for trade dress claims and unregistered mark protection.', '["No federal registration required — protects unregistered marks and trade dress","False association — use of word, term, name, symbol, or device likely to cause confusion as to origin, sponsorship, or approval (§ 1125(a)(1)(A))","False advertising — false or misleading description or representation of fact in commercial advertising (§ 1125(a)(1)(B))","Standing requires commercial injury — competitor or directly harmed party (Lexmark Int''l v. Static Control, 572 US 118 (2014))","Trade dress must be nonfunctional and either inherently distinctive or have acquired secondary meaning","Same remedies as registered mark infringement — injunction, damages, profits"]', '[{"section":"1125(a)(1)(A)","description":"False designation of origin — confusion as to source, sponsorship, or approval"},{"section":"1125(a)(1)(B)","description":"False advertising — misleading descriptions or representations of fact"},{"section":"1125(a)(3)","description":"Standing — any person who believes damaged by violation"},{"section":"1125(c)","description":"Dilution of famous marks — blurring and tarnishment"},{"section":"1125(d)","description":"Cybersquatting — bad faith registration of domain names"}]', '["unfair_competition_complaint","false_advertising_complaint","trade_dress_analysis","survey_evidence","consumer_confusion_study","cease_and_desist_letter"]', '["corporate-legal-architecture-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Copyright Act — Subject Matter & Scope
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_021', 'LEXARC', 'FEDERAL_STATUTE', 'US', '17 USC §§ 101-106 (Copyright Act — Subject Matter and Exclusive Rights)', 'Copyright Act §§ 101-106', 'Copyright Act — Subject Matter and Scope of Protection', 'Copyright protection subsists in original works of authorship fixed in a tangible medium of expression. Protection is automatic upon fixation — no registration required for copyright to exist. Eight categories of protectable works: literary, musical, dramatic, pantomime/choreographic, pictorial/graphic/sculptural, motion pictures, sound recordings, and architectural works. The copyright owner holds exclusive rights to reproduce, prepare derivative works, distribute, perform publicly, and display publicly.', '["Originality — minimal creativity threshold (Feist Publications v. Rural Telephone, 499 US 340 (1991))","Fixation in tangible medium of expression required (§ 102(a))","Eight categories of works of authorship (§ 102(a)(1)-(8))","Ideas, procedures, processes, systems, methods of operation not copyrightable (§ 102(b))","Exclusive rights — reproduction, derivative works, distribution, public performance, public display (§ 106)","Work made for hire — employer owns copyright (§ 101 definition, § 201(b))","Duration — life of author plus 70 years; 95 years from publication for works for hire (§ 302)","Fair use defense — purpose, nature, amount, market effect (§ 107)"]', '[{"section":"101","description":"Definitions — including work made for hire, publication, fixed"},{"section":"102(a)","description":"Subject matter — original works of authorship fixed in tangible medium"},{"section":"102(b)","description":"Exclusion — ideas, procedures, processes, systems not copyrightable"},{"section":"103","description":"Compilations and derivative works"},{"section":"106","description":"Exclusive rights — reproduce, derivative works, distribute, perform, display"},{"section":"106A","description":"Rights of attribution and integrity (VARA — visual artists)"},{"section":"107","description":"Fair use — four-factor balancing test"}]', '["copyright_registration","license_agreement","assignment_agreement","work_for_hire_agreement","fair_use_analysis","DMCA_notice"]', '["corporate-legal-architecture-audit"]', 'U.S. Copyright Office / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Copyright Act — Registration & Infringement
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_022', 'LEXARC', 'FEDERAL_STATUTE', 'US', '17 USC §§ 408-412, 501-505 (Copyright Act — Registration and Infringement)', 'Copyright Act §§ 408-412, 501-505', 'Copyright Act — Registration and Infringement Remedies', 'Registration with the Copyright Office is a prerequisite to filing an infringement suit for U.S. works. Timely registration (within 3 months of publication or before infringement) enables statutory damages ($750-$30,000 per work; up to $150,000 for willful infringement) and attorneys fees. Infringement requires proof of ownership and copying — either direct evidence or circumstantial proof of access plus substantial similarity.', '["Registration required before filing suit for U.S. works (§ 411(a); Fourth Estate v. Wall-Street.com, 139 S. Ct. 881 (2019))","Timely registration required for statutory damages and attorneys fees (§ 412)","Infringement — violation of any exclusive right under § 106 (§ 501)","Elements: (1) valid copyright, (2) copying of protectable elements","Actual damages plus infringer profits, or statutory damages at election (§ 504)","Statutory damages: $750-$30,000 per work infringed; up to $150,000 for willful infringement (§ 504(c))","Innocent infringer reduction to $200 per work (§ 504(c)(2))","Injunctive relief — temporary and permanent (§ 502)","Impoundment and disposition of infringing articles (§ 503)"]', '[{"section":"408","description":"Copyright registration in general — permissive"},{"section":"410","description":"Registration of claim — effective date and certificate"},{"section":"411","description":"Registration prerequisite to infringement suit"},{"section":"412","description":"Timely registration required for statutory damages and attorneys fees"},{"section":"501","description":"Infringement of copyright — cause of action"},{"section":"502","description":"Injunctive relief — temporary and final injunctions"},{"section":"503","description":"Impoundment and disposition of infringing articles"},{"section":"504","description":"Damages and profits — actual damages or statutory damages"},{"section":"505","description":"Costs and attorneys fees — court discretion"}]', '["copyright_registration","infringement_complaint","damages_expert_report","injunction_motion","DMCA_takedown","statutory_damages_election"]', '["corporate-legal-architecture-audit"]', 'U.S. Copyright Office / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- DMCA — Safe Harbors
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_023', 'LEXARC', 'FEDERAL_STATUTE', 'US', '17 USC § 512 (Digital Millennium Copyright Act — Online Service Provider Safe Harbors)', 'DMCA § 512', 'DMCA — Online Service Provider Safe Harbors', 'Limits liability of online service providers for copyright infringement by users when the OSP complies with specified conditions. Four safe harbors: (1) transitory digital network communications, (2) system caching, (3) information residing on systems at direction of users, and (4) information location tools. Requires designated DMCA agent, notice-and-takedown procedures, and termination policy for repeat infringers.', '["Designated DMCA agent registered with Copyright Office (§ 512(c)(2))","Notice-and-takedown — expeditious removal upon receiving compliant notice (§ 512(c)(1)(C))","Counter-notification procedure — put-back within 10-14 business days absent court order (§ 512(g))","No actual knowledge of infringing material (§ 512(c)(1)(A))","No financial benefit directly attributable to infringing activity where OSP has right and ability to control (§ 512(c)(1)(B))","Repeat infringer termination policy reasonably implemented (§ 512(i))","Accommodation of standard technical measures (§ 512(i)(1)(B))","Subpoena power to identify infringers (§ 512(h))"]', '[{"section":"512(a)","description":"Transitory digital network communications — conduit safe harbor"},{"section":"512(b)","description":"System caching safe harbor"},{"section":"512(c)","description":"Information stored at direction of users — hosting safe harbor"},{"section":"512(c)(3)","description":"Elements of a compliant DMCA takedown notice"},{"section":"512(d)","description":"Information location tools — search engine safe harbor"},{"section":"512(f)","description":"Misrepresentation in takedown notice — damages liability"},{"section":"512(g)","description":"Counter-notification and put-back procedure"},{"section":"512(i)","description":"Conditions for eligibility — repeat infringer policy and standard technical measures"}]', '["DMCA_takedown_notice","counter_notification","DMCA_agent_designation","repeat_infringer_policy","terms_of_service","copyright_policy"]', '["corporate-legal-architecture-audit"]', 'Federal Courts / U.S. Copyright Office', 1, 1, datetime('now'), datetime('now'));

-- Patent Act — Patentability
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_024', 'LEXARC', 'FEDERAL_STATUTE', 'US', '35 USC §§ 100-105 (Patent Act — Patentability)', 'Patent Act §§ 100-105', 'Patent Act — Conditions for Patentability', 'Establishes the requirements for patentability of inventions. Patent protection grants the inventor a 20-year monopoly (from filing date) in exchange for public disclosure. Four conditions: (1) patentable subject matter, (2) novelty, (3) nonobviousness, and (4) utility. The America Invents Act (2011) converted the U.S. to a first-inventor-to-file system effective March 16, 2013. Abstract ideas, laws of nature, and natural phenomena are not patentable subject matter (Alice Corp. v. CLS Bank, 573 US 208 (2014)).', '["Patentable subject matter — process, machine, manufacture, or composition of matter (§ 101)","Utility — invention must be useful (§ 101)","Novelty — invention must not be anticipated by prior art (§ 102)","First-inventor-to-file priority system (§ 102, AIA amendment)","Nonobviousness — invention must not be obvious to person of ordinary skill in art (§ 103)","Specification must enable person of ordinary skill to make and use invention (§ 112)","Claims define scope of patent protection (§ 112)","20-year term from earliest U.S. filing date (§ 154)","Judicial exceptions: abstract ideas, laws of nature, natural phenomena (Alice/Mayo framework)"]', '[{"section":"100","description":"Definitions — invention, process, patent, inventor"},{"section":"101","description":"Inventions patentable — process, machine, manufacture, composition of matter"},{"section":"102","description":"Conditions for patentability — novelty and prior art"},{"section":"103","description":"Conditions for patentability — nonobviousness"},{"section":"112","description":"Specification — written description, enablement, claims"},{"section":"154","description":"Contents and term of patent — 20 years from filing"}]', '["patent_application","prior_art_search","office_action_response","claims_amendment","continuation_application","patent_grant"]', '["corporate-legal-architecture-audit"]', 'USPTO / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Defend Trade Secrets Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_025', 'LEXARC', 'FEDERAL_STATUTE', 'US', '18 USC § 1836 (Defend Trade Secrets Act of 2016)', 'DTSA § 1836', 'Defend Trade Secrets Act', 'Creates a federal private civil cause of action for trade secret misappropriation. Enacted in 2016 to supplement (not preempt) state trade secret laws. Authorizes ex parte seizure orders in extraordinary circumstances to prevent dissemination. Provides for actual damages plus unjust enrichment, or reasonable royalty. Willful and malicious misappropriation may result in exemplary damages up to 2x actual damages plus attorneys fees. Includes a whistleblower immunity provision requiring notice in employee agreements.', '["Federal civil cause of action for trade secret misappropriation (§ 1836(b))","Trade secret must derive economic value from not being generally known and be subject to reasonable secrecy measures (§ 1839(3))","Misappropriation by improper means or breach of duty (§ 1839(5))","Ex parte seizure in extraordinary circumstances (§ 1836(b)(2))","3-year statute of limitations from discovery (§ 1836(d))","Actual damages plus unjust enrichment, or reasonable royalty (§ 1836(b)(3)(B))","Exemplary damages up to 2x for willful and malicious misappropriation (§ 1836(b)(3)(C))","Attorneys fees for willful/malicious misappropriation or bad faith claim (§ 1836(b)(3)(D))","Whistleblower immunity notice required in employee agreements (§ 1833(b))"]', '[{"section":"1836(b)(1)","description":"Private civil action — owner of trade secret may bring action in federal court"},{"section":"1836(b)(2)","description":"Ex parte seizure — extraordinary circumstances to prevent propagation"},{"section":"1836(b)(3)(A)","description":"Injunctive relief — conditions and limitations"},{"section":"1836(b)(3)(B)","description":"Damages — actual loss, unjust enrichment, or reasonable royalty"},{"section":"1836(b)(3)(C)","description":"Exemplary damages — up to 2x for willful and malicious"},{"section":"1836(d)","description":"Statute of limitations — 3 years from date misappropriation discovered or should have been"},{"section":"1833(b)","description":"Whistleblower immunity — required notice in NDA/employment agreements"},{"section":"1839(3)","description":"Definition of trade secret — economic value from secrecy plus reasonable measures"}]', '["trade_secret_complaint","ex_parte_seizure_motion","NDA_with_whistleblower_notice","trade_secret_inventory","reasonable_measures_audit","injunction_motion"]', '["corporate-legal-architecture-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- LEXARC — California Intellectual Property
-- ═══════════════════════════════════════════════════════════════════════════

-- CA Uniform Trade Secrets Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_026', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 3426-3426.11 (California Uniform Trade Secrets Act)', 'CC §§ 3426-3426.11', 'California Uniform Trade Secrets Act', 'California enactment of the Uniform Trade Secrets Act providing state-law remedies for misappropriation of trade secrets. Supersedes other state civil remedies for trade secret misappropriation except contractual claims. Trade secrets include formulas, patterns, compilations, programs, devices, methods, techniques, or processes that derive independent economic value from not being generally known. CUTSA is the exclusive civil remedy for trade secret misappropriation under California law, preempting common law tort claims based on the same nucleus of facts.', '["Trade secret must derive independent economic value from secrecy (§ 3426.1(d))","Owner must take reasonable measures to maintain secrecy (§ 3426.1(d))","Misappropriation includes acquisition by improper means or breach of duty (§ 3426.1(b))","Injunctive relief — reasonable period to eliminate commercial advantage (§ 3426.2)","Actual damages including unjust enrichment not captured by damages (§ 3426.3)","Exemplary damages up to 2x for willful and malicious misappropriation (§ 3426.3(c))","Attorneys fees for bad faith claim or willful/malicious misappropriation (§ 3426.4)","3-year statute of limitations from discovery or when should have been discovered (§ 3426.6)","CUTSA preempts other civil remedies based on trade secret misappropriation (§ 3426.7)"]', '[{"section":"3426.1","description":"Definitions — trade secret, misappropriation, improper means"},{"section":"3426.2","description":"Injunctive relief — scope and duration"},{"section":"3426.3","description":"Damages — actual loss plus unjust enrichment, or reasonable royalty"},{"section":"3426.3(c)","description":"Exemplary damages — up to 2x for willful and malicious misappropriation"},{"section":"3426.4","description":"Attorneys fees — bad faith or willful/malicious conduct"},{"section":"3426.5","description":"Preservation of secrecy — protective orders during litigation"},{"section":"3426.6","description":"Statute of limitations — 3 years from discovery"},{"section":"3426.7","description":"CUTSA preemption — exclusive civil remedy for trade secret misappropriation"}]', '["trade_secret_complaint","NDA","protective_order","trade_secret_log","injunction_motion","damages_calculation"]', '["corporate-legal-architecture-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Right of Publicity
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_027', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 3344 (Right of Publicity)', 'CC § 3344', 'California Right of Publicity', 'Statutory right of publicity prohibiting unauthorized commercial use of a person''s name, voice, signature, photograph, or likeness. Applies to living persons (§ 3344) and deceased personalities (§ 3344.1 — post-mortem rights for 70 years after death). Plaintiff must prove knowing use for commercial purposes without consent. Damages include greater of actual damages or $750 statutory minimum, plus profits attributable to the use, and punitive damages for knowing violations.', '["Unauthorized use of name, voice, signature, photograph, or likeness (§ 3344(a))","Use must be on or in products, merchandise, goods, services, or for advertising/selling purposes","Defendant must knowingly use plaintiff identity for commercial purpose","Consent is a complete defense","Newsworthy and public affairs exemptions (§ 3344(d))","Post-mortem rights — 70 years after death for deceased personalities (§ 3344.1)","Statutory minimum damages of $750 per unauthorized use (§ 3344(a))","Profits attributable to the unauthorized use (§ 3344(a))","Punitive damages available (§ 3344(a))","Attorneys fees and costs to prevailing party (§ 3344(a))"]', '[{"section":"3344(a)","description":"Liability for unauthorized commercial use of identity — name, voice, signature, photograph, likeness"},{"section":"3344(b)","description":"Consent defense — prior written consent of person"},{"section":"3344(d)","description":"Exemptions — news, public affairs, sports broadcast, political campaigns"},{"section":"3344(e)","description":"Definition — photograph and likeness"},{"section":"3344.1","description":"Post-mortem right of publicity — deceased personality rights for 70 years"}]', '["right_of_publicity_complaint","consent_release","licensing_agreement","cease_and_desist_letter","damages_calculation"]', '["corporate-legal-architecture-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- LEXARC — Securities Law
-- ═══════════════════════════════════════════════════════════════════════════

-- Securities Act 1933 — Registration
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_028', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC §§ 77a-77aa (Securities Act of 1933)', 'Securities Act of 1933', 'Securities Act of 1933 — Registration of Securities', 'Requires registration of securities offerings with the SEC unless an exemption applies. The fundamental purpose is to ensure investors receive material financial and other information concerning securities offered for public sale. Section 5 prohibits the sale or offer to sell securities unless a registration statement is in effect. Section 11 provides strict liability for material misstatements in registration statements. Section 12 provides private right of action for unregistered sales and prospectus fraud.', '["Registration statement (Form S-1) required before public offering (§ 77e)","Prospectus must contain all material information (§ 77j)","Gun-jumping rules — restrictions on offers/sales during waiting period (§ 77e(a)-(c))","Section 11 — strict liability for material misstatements in registration statement (§ 77k)","Section 12(a)(1) — rescission for sale of unregistered securities (§ 77l(a)(1))","Section 12(a)(2) — liability for prospectus fraud — material misstatement or omission (§ 77l(a)(2))","Exemptions — private placements (§ 4(a)(2)), intrastate offerings (§ 3(a)(11)), accredited investors (Reg D)","1-year statute of limitations, 3-year statute of repose (§ 77m)"]', '[{"section":"77b","description":"Definitions — security, sale, offer, issuer, underwriter"},{"section":"77e","description":"Section 5 — prohibition on sale/offer without effective registration statement"},{"section":"77f","description":"Registration of securities — filing and effective date"},{"section":"77j","description":"Information required in prospectus"},{"section":"77k","description":"Section 11 — civil liability for false registration statement"},{"section":"77l","description":"Section 12 — civil liability for unregistered sale or prospectus fraud"},{"section":"77m","description":"Statute of limitations — 1 year from discovery, 3 year repose"},{"section":"77d","description":"Exempt transactions — § 4(a)(1) ordinary trading, § 4(a)(2) private placements"}]', '["registration_statement","prospectus","SEC_filing","offering_memorandum","subscription_agreement","underwriting_agreement","Form_S_1"]', '["corporate-legal-architecture-audit"]', 'SEC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Securities Exchange Act 1934 — Rule 10b-5
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_029', 'LEXARC', 'FEDERAL_REGULATION', 'US', '17 CFR § 240.10b-5 (SEC Rule 10b-5 — Employment of Manipulative and Deceptive Devices)', 'Rule 10b-5', 'SEC Rule 10b-5 — Securities Fraud', 'The most important antifraud provision in federal securities law. Prohibits any act or omission resulting in fraud or deceit in connection with the purchase or sale of any security. Implied private right of action established by case law. Elements of a private 10b-5 claim: (1) material misrepresentation or omission, (2) scienter (intent to deceive or severe recklessness), (3) connection with purchase or sale of security, (4) reliance, (5) economic loss, and (6) loss causation. Applies to insider trading under the classical and misappropriation theories.', '["Material misrepresentation or omission of fact (Rule 10b-5(b))","Scienter — intent to deceive, manipulate, or defraud (Ernst & Ernst v. Hochfelder, 425 US 185 (1976))","In connection with purchase or sale of security (SEC v. Zandford, 535 US 813 (2002))","Reliance — transaction causation (Basic v. Levinson fraud-on-the-market presumption, 485 US 224 (1988))","Economic loss and loss causation (Dura Pharmaceuticals v. Broudo, 544 US 336 (2005))","Insider trading — classical theory (Chiarella) and misappropriation theory (O''Hagan)","PSLRA heightened pleading standards for scienter (15 USC § 78u-4)","2-year/5-year statute of limitations/repose (28 USC § 1658(b))"]', '[{"section":"240.10b-5(a)","description":"Prohibition on employing any device, scheme, or artifice to defraud"},{"section":"240.10b-5(b)","description":"Prohibition on material misstatements or omissions"},{"section":"240.10b-5(c)","description":"Prohibition on any act which operates as fraud or deceit"},{"section":"240.10b5-1","description":"Trading on material nonpublic information — affirmative defense plans"},{"section":"240.10b5-2","description":"Duties of trust or confidence for misappropriation theory"}]', '["securities_fraud_complaint","10b-5_demand_letter","insider_trading_report","Section_16_filing","10b5-1_trading_plan","SEC_enforcement_action"]', '["corporate-legal-architecture-audit"]', 'SEC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Regulation D — Private Placements
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_030', 'LEXARC', 'FEDERAL_REGULATION', 'US', '17 CFR §§ 230.501-508 (SEC Regulation D — Rules Governing Limited Offer and Sale of Securities)', 'Reg D §§ 501-508', 'SEC Regulation D — Private Placement Exemptions', 'Safe harbor rules providing exemptions from Securities Act registration for private offerings. Three principal exemptions: Rule 504 (offerings up to $10 million), Rule 506(b) (unlimited amount, no general solicitation, up to 35 non-accredited sophisticated investors), and Rule 506(c) (unlimited amount, general solicitation permitted, all purchasers must be verified accredited investors). Rule 506 offerings preempt state registration requirements under NSMIA. Form D filing required within 15 days of first sale.', '["Accredited investor definition — income over $200K ($300K joint) or net worth over $1M excluding primary residence (Rule 501(a))","Rule 504 — offerings up to $10 million in 12 months","Rule 506(b) — unlimited amount, no general solicitation, up to 35 non-accredited investors who are sophisticated","Rule 506(c) — unlimited amount, general solicitation permitted, all purchasers must be verified accredited investors","Form D notice filing with SEC within 15 days of first sale (Rule 503)","Bad actor disqualification for certain felons and securities violators (Rule 506(d))","Integration doctrine — separate offerings may be treated as one (Rule 502(a))","Resale restrictions — securities are restricted, legend required (Rule 502(d))","State preemption under NSMIA for Rule 506 offerings — notice filing only"]', '[{"section":"230.501","description":"Definitions — accredited investor, purchaser representative"},{"section":"230.502","description":"General conditions — integration, information requirements, resale limitations"},{"section":"230.503","description":"Form D notice filing requirement"},{"section":"230.504","description":"Rule 504 — exemption for limited offerings up to $10 million"},{"section":"230.506(b)","description":"Rule 506(b) — exemption without general solicitation, up to 35 non-accredited"},{"section":"230.506(c)","description":"Rule 506(c) — exemption with general solicitation, verified accredited only"},{"section":"230.506(d)","description":"Bad actor disqualification provisions"},{"section":"230.508","description":"Insignificant deviations from Reg D requirements"}]', '["private_placement_memorandum","subscription_agreement","accredited_investor_questionnaire","Form_D","investor_suitability","offering_memorandum","restricted_stock_legend"]', '["corporate-legal-architecture-audit"]', 'SEC', 0, 1, datetime('now'), datetime('now'));

-- CA Corporate Securities Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_031', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Corp. Code §§ 25000-25707 (California Corporate Securities Law of 1968)', 'Corp Code § 25000+', 'California Corporate Securities Law of 1968', 'California blue sky law regulating the offer and sale of securities within the state. Uses qualification (permit) system rather than federal registration approach — Commissioner of Financial Protection and Innovation must qualify offerings unless exempt. Section 25110 requires qualification before any offer or sale. Section 25401 prohibits material misstatements or omissions in connection with securities transactions. Section 25501 provides a private right of action for securities fraud. NSMIA preempts state registration for Rule 506 offerings but California retains antifraud jurisdiction.', '["Qualification (permit) required before offer or sale of securities (§ 25110)","Commissioner of Financial Protection and Innovation reviews and qualifies offerings","Exemptions — § 25102(f) limited offering exemption (up to 35 purchasers), § 25102(n) accredited investor exemption","§ 25401 — unlawful to make material misstatement or omission in securities offer/sale","§ 25501 — private right of action for violation of § 25401 — rescission or damages","§ 25504 — joint and several liability for control persons and aiders","§ 25540 — criminal penalties for willful violations","Notice filing required for Rule 506 offerings — Form D-506"]', '[{"section":"25102","description":"Exempt transactions — enumerated exemptions from qualification"},{"section":"25102(f)","description":"Limited offering exemption — up to 35 purchasers with suitability"},{"section":"25110","description":"Qualification requirement — no offer or sale without qualification or exemption"},{"section":"25113","description":"Qualification by permit — application to Commissioner"},{"section":"25401","description":"Antifraud — material misstatement or omission prohibition"},{"section":"25501","description":"Private right of action — rescission or damages for securities fraud"},{"section":"25504","description":"Joint and several liability — controlling persons and aiders"},{"section":"25540","description":"Criminal penalties — fine up to $10 million and/or imprisonment up to 10 years"}]', '["qualification_application","25102f_notice","offering_circular","subscription_agreement","Form_D_506_notice","investor_suitability_questionnaire","blue_sky_opinion"]', '["corporate-legal-architecture-audit"]', 'California DFPI (Department of Financial Protection and Innovation)', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- LEXARC — Antitrust and Competition Law
-- ═══════════════════════════════════════════════════════════════════════════

-- Sherman Antitrust Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_032', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC §§ 1-7 (Sherman Antitrust Act)', 'Sherman Act §§ 1-7', 'Sherman Antitrust Act', 'Primary federal antitrust statute prohibiting (1) contracts, combinations, and conspiracies in restraint of trade (§ 1), and (2) monopolization, attempted monopolization, and conspiracy to monopolize (§ 2). Section 1 requires concerted action — agreement between two or more entities. Section 2 applies to unilateral conduct. Per se violations include price fixing, bid rigging, and market allocation. Rule of reason analysis applies to most other restraints. Criminal penalties include up to $100 million for corporations and 10 years imprisonment for individuals.', '["§ 1 — Every contract, combination, or conspiracy in restraint of trade is illegal","§ 2 — Monopolization, attempted monopolization, or conspiracy to monopolize is illegal","Per se violations — price fixing, bid rigging, market allocation, group boycotts","Rule of reason — balances procompetitive justifications against anticompetitive harm","§ 1 requires agreement/concerted action between separate entities","§ 2 applies to unilateral conduct — monopoly power plus willful acquisition/maintenance","Criminal penalties: corporations up to $100 million fine; individuals up to $1 million fine and 10 years imprisonment","Treble damages for private plaintiffs under Clayton Act § 4 (15 USC § 15)"]', '[{"section":"1","description":"Restraint of trade — contracts, combinations, conspiracies declared illegal"},{"section":"2","description":"Monopolization — monopolizing, attempting to monopolize, or conspiring to monopolize"},{"section":"3","description":"Restraint of trade in territories and D.C."},{"section":"4","description":"Jurisdiction of courts — equity proceedings by government"},{"section":"6","description":"Property in transit — forfeiture"},{"section":"7","description":"Definitions — person includes corporations and associations"}]', '["antitrust_complaint","DOJ_investigation","consent_decree","market_analysis","merger_review","leniency_application","treble_damages_complaint"]', '["corporate-legal-architecture-audit"]', 'DOJ Antitrust Division / FTC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Clayton Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_033', 'LEXARC', 'FEDERAL_STATUTE', 'US', '15 USC §§ 12-27 (Clayton Antitrust Act)', 'Clayton Act §§ 12-27', 'Clayton Antitrust Act', 'Supplements the Sherman Act by addressing specific anticompetitive practices. Prohibits price discrimination (§ 2, as amended by Robinson-Patman Act), tying arrangements and exclusive dealing (§ 3), and mergers and acquisitions that may substantially lessen competition (§ 7). Section 4 creates the private treble damages remedy — any person injured by antitrust violation may recover threefold damages plus attorneys fees. Section 16 authorizes private injunctive relief. Hart-Scott-Rodino Act (§ 7A) requires pre-merger notification for transactions above threshold.', '["§ 2 — Price discrimination prohibited where effect may substantially lessen competition (Robinson-Patman Act)","§ 3 — Tying arrangements and exclusive dealing contracts prohibited","§ 4 — Private treble damages action — any person injured in business or property","§ 4 — Standing requires antitrust injury — injury of the type the antitrust laws were intended to prevent","§ 7 — Mergers and acquisitions prohibited where effect may be to substantially lessen competition","§ 7A (HSR Act) — Pre-merger notification required above threshold ($119.5M in 2025)","§ 16 — Private parties may seek injunctive relief","4-year statute of limitations (§ 4B)"]', '[{"section":"12","description":"Definitions — antitrust laws, commerce, person"},{"section":"13","description":"Price discrimination (Robinson-Patman Act amendment)"},{"section":"14","description":"Tying and exclusive dealing — sale on condition of not dealing with competitor"},{"section":"15","description":"Treble damages — any person injured may sue for threefold damages plus attorneys fees"},{"section":"18","description":"Mergers — acquisition of stock or assets where effect may substantially lessen competition"},{"section":"18a","description":"Hart-Scott-Rodino pre-merger notification — filing and waiting period"},{"section":"26","description":"Injunctive relief for private parties"}]', '["antitrust_complaint","treble_damages_complaint","HSR_filing","merger_review","second_request","consent_decree","competitive_impact_statement"]', '["corporate-legal-architecture-audit"]', 'DOJ Antitrust Division / FTC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Cartwright Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_034', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 16700-16770 (Cartwright Act)', 'BPC §§ 16700-16770', 'California Cartwright Act', 'California''s principal antitrust statute, broader than the federal Sherman Act. Prohibits trusts — combinations to restrain trade, prevent competition, fix prices, or control production. Unlike the Sherman Act, the Cartwright Act covers combinations involving a single entity and its agents. Provides treble damages to any person injured by a trust violation. California courts apply both per se and rule of reason analysis. The Cartwright Act reaches horizontal and vertical restraints, and indirect purchasers have standing to sue (unlike federal antitrust law under Illinois Brick).', '["Trust defined — combination to create or carry out restrictions in trade, limit production, fix prices, or prevent competition (§ 16720)","Broadly covers any person — including single entity acting through agents","Per se violations include price fixing, bid rigging, and market allocation","Rule of reason applies to most vertical restraints","Treble damages for any person injured directly or indirectly (§ 16750)","Indirect purchaser standing — California rejects Illinois Brick doctrine","Attorney General enforcement authority — civil and criminal (§ 16754)","Criminal penalties — felony with fine and/or imprisonment (§ 16755)","4-year statute of limitations (§ 16750.1)"]', '[{"section":"16720","description":"Trust defined — combination to restrain trade, fix prices, prevent competition"},{"section":"16726","description":"Non-compete agreements — prohibition (except as to sale of business or dissolution of partnership)"},{"section":"16750","description":"Private right of action — treble damages for persons injured by trust"},{"section":"16750.1","description":"Statute of limitations — 4 years"},{"section":"16754","description":"Attorney General enforcement — actions for injunctive relief"},{"section":"16755","description":"Criminal penalties — felony for trust violations"}]', '["antitrust_complaint","treble_damages_complaint","AG_enforcement_action","market_analysis","competitive_impact_analysis","injunction_motion"]', '["corporate-legal-architecture-audit"]', 'California Attorney General / California Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- LEXARC — Business Torts
-- ═══════════════════════════════════════════════════════════════════════════

-- CA Unfair Competition Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_lex_035', 'LEXARC', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 17200-17210 (Unfair Competition Law)', 'BPC §§ 17200-17210', 'California Unfair Competition Law (UCL)', 'California''s broadest consumer protection and business tort statute. Defines unfair competition as any unlawful, unfair, or fraudulent business act or practice and any false or misleading advertising. Three independent prongs: (1) unlawful — violation of any other law, (2) unfair — conduct whose harm outweighs utility, and (3) fraudulent — conduct likely to deceive members of the public. Standing requires loss of money or property as a result of unfair competition (Prop 64, 2004). Remedies limited to restitution and injunctive relief — no damages or penalties in private actions.', '["Unlawful prong — borrows from any federal, state, or local law violation as predicate (§ 17200)","Unfair prong — business practice whose harm to victim outweighs any legitimate utility","Fraudulent prong — conduct likely to deceive reasonable members of the public","Standing — private plaintiff must have suffered injury in fact and lost money or property (§ 17204, Prop 64)","Remedies in private action limited to restitution and injunctive relief — no damages (§ 17203)","Attorney General, district attorney, and certain city attorneys may seek civil penalties up to $2,500 per violation (§ 17206)","4-year statute of limitations (§ 17208)","Representative actions under § 17203 — standing requirements apply to named plaintiff","Prevailing defendant not entitled to attorneys fees absent contractual or statutory basis"]', '[{"section":"17200","description":"Unfair competition defined — unlawful, unfair, or fraudulent business act or practice"},{"section":"17201","description":"Definitions — unfair competition includes false advertising under § 17500"},{"section":"17203","description":"Remedies — injunction, restitution, and disgorgement of money or property"},{"section":"17204","description":"Standing — person who has suffered injury in fact and lost money or property"},{"section":"17206","description":"Civil penalties — AG, DA, or city attorney may seek up to $2,500 per violation"},{"section":"17208","description":"Statute of limitations — 4 years"}]', '["UCL_complaint","restitution_motion","injunction_motion","unfair_business_practice_analysis","consumer_complaint","AG_enforcement_action"]', '["corporate-legal-architecture-audit"]', 'California Attorney General / District Attorney / California Courts', 1, 1, datetime('now'), datetime('now'));
